func:
let scenario = flow.get("scenario") || "normal";

if (msg.topic) {
  flow.set("scenario", msg.topic);
  node.status({ fill: "blue", shape: "dot", text: "escenario: " + msg.topic });
  return null;
}

const byScenario = {
  normal: { wind: 8.2, volt: 48.6, curr: 8.0, vib: 2.4, temp: 54, batt: 75, load: 520 },
  poco_viento: { wind: 1.8, volt: 0.0, curr: 0.0, vib: 2.2, temp: 53, batt: 66, load: 340 },
  viento_peligroso: { wind: 23.0, volt: 48.6, curr: 8.2, vib: 2.7, temp: 56, batt: 74, load: 560 },
  temperatura_alta: { wind: 8.4, volt: 48.5, curr: 8.1, vib: 2.5, temp: 85, batt: 72, load: 540 },
  vibracion_alta: { wind: 8.1, volt: 48.4, curr: 7.8, vib: 7.1, temp: 55, batt: 71, load: 530 },
  bateria_baja: { wind: 7.9, volt: 48.3, curr: 7.7, vib: 2.6, temp: 54, batt: 15, load: 540 },
  demanda_alta: { wind: 9.0, volt: 48.8, curr: 8.4, vib: 2.3, temp: 55, batt: 62, load: 900 },
  alerta_total: { wind: 24.0, volt: 48.7, curr: 8.2, vib: 7.2, temp: 86, batt: 14, load: 600 }
};

scenario = flow.get("scenario") || scenario;
const base = byScenario[scenario] || byScenario.normal;
const jitter = (v, j) => Number((v + (Math.random() * 2 - 1) * j).toFixed(2));
const clamp = (v, min, max) => Math.max(min, Math.min(max, v));

const jitterByScenario = scenario === "poco_viento" ? { wind: 0.1, volt: 0.04, curr: 0.05 } : { wind: 0.25, volt: 0.3, curr: 0.5 };

const state = {
  wind: clamp(jitter(base.wind, jitterByScenario.wind), 0, 30),
  volt: clamp(jitter(base.volt, jitterByScenario.volt), 0, 90),
  curr: clamp(jitter(base.curr, jitterByScenario.curr), 0, 120),
  vib: clamp(jitter(base.vib, 0.12), 0, 15),
  temp: clamp(jitter(base.temp, 0.35), -10, 120),
  batt: clamp(jitter(base.batt, 0.35), 0, 100),
  load: clamp(jitter(base.load, 8), 100, 3000)
};

if (scenario === "poco_viento") {
  state.volt = 0;
  state.curr = 0;
}

msg.headers = {
  "Content-Type": "application/json",
  "x-api-key": env.get("INGEST_API_KEY") || "dev-ingest-key"
};

const apiBase = (env.get("API_BASE") || "http://localhost:3000").replace(/\/+$/, "");
msg.url = apiBase + "/api/v1/readings/ingest";

msg.payload = {
  deviceId: env.get("DEVICE_ID") || "AE-01",
  farmId: env.get("FARM_ID") || "FARM-01",
  plotId: env.get("PLOT_ID") || "PLOT-01",
  ts: new Date().toISOString(),
  windSpeedMs: state.wind,
  genVoltageV: state.volt,
  genCurrentA: state.curr,
  vibrationRms: state.vib,
  genTempC: state.temp,
  batteryPct: Math.round(state.batt),
  loadPowerW: Math.round(state.load),
  mode: "node-red:" + scenario
};

node.status({ fill: "green", shape: "dot", text: "enviando: " + scenario });
return msg;
